      teamHeaders: [
        { text: 'Layer', value: 'layer' },
        { text: 'Commission Percentage', value: 'percent' },
        { text: 'Point From', value: 'from' },
      ],      
    }
  },
  computed: {
    bvMobile: {
      get() {
        return this.$store.state.bvMobile * 100;
      },
      set(value) {
        this.$store.commit('setBvMobile', value / 100);
      },
    }, 
    bvEnergy: {
      get() {
        return this.$store.state.bvEnergy * 100;
      },
      set(value) {
        this.$store.commit('setBvEnergy', value / 100);
      },
    },
    bvInternet: {
      get() {
        return this.$store.state.bvInternet * 100;
      },
      set(value) {
        this.$store.commit('setBvInternet', value / 100);
      },
    },
    pointMobile: {
      get() {
        return this.$store.state.pointMobile;
      },
      set(value) {
        this.$store.commit('setPointMobile', value);
      },
    }, 
    pointEnergy: {
      get() {
        return this.$store.state.pointEnergy;
      },
      set(value) {
        this.$store.commit('setPointEnergy', value);
      },
    },
    pointInternet: {
      get() {
        return this.$store.state.pointInternet;
      },
      set(value) {
        this.$store.commit('setPointInternet', value);
      },
    },    
    iboRegistryFee: {
      get() {
        return this.$store.state.iboRegistryFee;
      },
      set(value) {
        this.$store.commit('setIboRegistryFee', value);
      },
    },
    iboRenewalFee: {
      get() {
        return this.$store.state.iboRenewalFee;
      },
      set(value) {
        this.$store.commit('setIboRenewalFee', value);
      },
    },     
    ...mapState({
      personalConfigs: state => state.personalConfigs,
      teamConfigs: state => state.teamConfigs,
    })
